    val pkg = parts.getOrNull(0)?.trim().let { if (it == "null" || it == "") null else it }
    val mins = parts.getOrNull(1)?.trim()?.toLongOrNull() ?: 5L
    val depth = parts.getOrNull(2)?.trim()?.toIntOrNull() ?: 10

